class Solution:
    def popcountDepth(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        def popcount(x):
            return bin(x).count('1')

        def get_popcount_depth(x):
            depth = 0
            while popcount(x) != 1:
                x = popcount(x)
                depth += 1
            return depth

        n = len(nums)
        answer = []
        for query in queries:
            if query[0] == 1:
                l, r, k = query[1], query[2], query[3]
                count = 0
                for i in range(l, r + 1):
                    if get_popcount_depth(nums[i]) == k:
                        count += 1
                answer.append(count)
            elif query[0] == 2:
                idx, val = query[1], query[2]
                nums[idx] = val

        return answer
```

efficiency: HIGH
time complexity: O(N * Q * (logM + logN)), where N is the length of nums, Q is the number of queries, M is the maximum value in nums, and N is the length of nums.
space complexity: O(N)
energy implications: MEDIUM

